----------------------------------------------------------------------
-- DCS Civil Mission Template - Firefighting
-- File: 10_CivilFirefighting.lua  (requires 01_CivilCore.lua)
--
-- Fire zone manager + helicopter water ops + C-130 retardant ops.
--
--   FIRES: random ignition among the curated "CIVIL Fire Point" zones,
--   smoke/fire via trigger.action.effectSmokeBig/effectSmokeStop, per-zone
--   active state, growth rate randomized ONCE per fire.
--
--   HELICOPTERS: hover over a "CIVIL Water Point" (safe height, not skimming)
--   -> water loaded -> drop over an active fire. Two modes
--   (CIV.Config.fire.usePhysicalCargo):
--     false (default): logical per-unit load + F10 drop. Robust.
--     true (EXPERIMENTAL): spawns a native mass Cargo object to sling with
--     F8; cargo spawn on open water is UNTESTED in-game (see docs).
--
--   C-130: no in-flight scooping (that is amphibian work). Ground reload in
--   the "CIVIL C130 Reload" zone (logical state, DCS has no native
--   retardant), then a line drop across the fire region at moderate AGL.
--   Any player airplane inside the fire region also acts as SPOTTER,
--   relaying fire coordinates and F10 marks to the coalition.
----------------------------------------------------------------------

assert(CIV and CIV.VERSION, "01_CivilCore.lua must be loaded first")

local C = CIV.Config
local CF = C.fire

----------------------------------------------------------------------
-- FIRE ZONE MANAGER (severity model)
-- Every fire carries a severity from 1 to 10, rolled at ignition and
-- growing on a per-fire randomized cadence. Visuals scale with severity:
-- a small fire is a single smoke/fire effect; as it grows, sub-fires
-- light up around the anchor (capped at severity.maxEffects simultaneous
-- effects for performance; effect SIZE keeps scaling past the cap).
-- Suppression (helicopter drops, C-130 line/airdrop, fire trucks on
-- scene) subtracts severity; at 0 the fire is out.
----------------------------------------------------------------------

CIV.Fire = { _fires = {}, _fid = 0 }
local Fire = CIV.Fire
local SEV = CF.severity
local dispatchFireTrucks, releaseFireTrucks   -- defined in the brigade section

-- effectSmokeBig presets: 1..4 = smoke+fire S/M/L/XL, 5..8 = thick smoke
-- only (used by smokeOnly fire kinds such as a landfill fire)
local function presetFor(severity, kindDef)
  local preset = math.max(1, math.min(4, math.ceil(severity / 2.5)))
  if kindDef and kindDef.smokeOnly then preset = preset + 4 end
  return preset
end

local function effectCountFor(severity)
  return math.max(1, math.min(SEV.maxEffects, math.ceil(severity / 2)))
end

function Fire.count()
  local n = 0
  for _ in pairs(Fire._fires) do n = n + 1 end
  return n
end

function Fire.actives() return Fire._fires end

function Fire.severityLabel(fire)
  return string.format("severity %d/10", math.ceil(fire.severity))
end

-- Bring the smoke/fire effect cluster in line with the current severity:
-- add sub-fires as it grows, stop them as it shrinks, resize on preset
-- change. Each effect keeps a stable random offset inside the fire zone.
local function refreshVisuals(fire)
  local wanted = effectCountFor(fire.severity)
  local preset = presetFor(fire.severity, fire.kindDef)
  for i = #fire.effects + 1, wanted do
    local p = fire.point
    if i > 1 then
      p = CIV.offsetPoint(fire.point, math.random(0, 359),
        math.random(30, math.max(40, math.floor(fire.pt.radius * 0.8))))
    end
    fire.effects[i] = { point = p, name = fire.smokeName .. "_" .. i, preset = 0 }
  end
  for i = #fire.effects, wanted + 1, -1 do
    trigger.action.effectSmokeStop(fire.effects[i].name)
    fire.effects[i] = nil
  end
  for _, eff in ipairs(fire.effects) do
    if eff.preset ~= preset then
      if eff.preset ~= 0 then trigger.action.effectSmokeStop(eff.name) end
      eff.preset = preset
      trigger.action.effectSmokeBig(eff.point, preset, 0.7, eff.name)
    end
  end
end

function Fire.ignite(pt, severityOverride)
  Fire._fid = Fire._fid + 1
  -- kind picked by weight: forest (fire), landfill (dark smoke, slow),
  -- industrial (fast growth); tells the players from afar what is burning
  local kindDef = CIV.weightedPick(CF.kinds)
  local fire = {
    id = Fire._fid, pt = pt, kindDef = kindDef,
    point = { x = pt.point.x, y = pt.point.y, z = pt.point.z },
    severity = severityOverride
      and math.max(1, math.min(SEV.max, severityOverride))
      or math.random(SEV.initial.min, SEV.initial.max),
    growEvery = CIV.randBetween(SEV.growEvery) / kindDef.growMult,
    smokeName = "CIVIL_FIRE_" .. Fire._fid,
    effects = {}, markId = nil,
  }
  fire.nextGrow = timer.getTime() + fire.growEvery
  refreshVisuals(fire)
  Fire._fires[fire.id] = fire
  CIV.Pool.occupy(pt)
  fire.zoneMarkId = CIV.drawEventZone(pt.area,
    string.upper(kindDef.name) .. " " .. pt.name, "fire")
  CIV.msgAll(string.upper(kindDef.name) .. " reported at " .. pt.name ..
    " (" .. Fire.severityLabel(fire) .. ")\n" .. CIV.coordText(fire.point) ..
    "\nFire zone highlighted on the F10 map.", 20)
  CIV.log("Fire #" .. fire.id .. " (" .. kindDef.name .. ") ignited at " ..
    pt.name .. " severity " .. fire.severity)
  dispatchFireTrucks(fire)
  return fire
end

function Fire.igniteRandom()
  if Fire.count() >= CF.maxActive then return nil end
  local pt = CIV.Pool.pick(C.zones.firePoints, 1000)
  if not pt then return nil end
  return Fire.ignite(pt)
end

-- command center: ignite at an arbitrary commanded position
function Fire.igniteAt(point, severity)
  Fire._fid = Fire._fid + 1
  local pt = {
    name = "GM fire " .. Fire._fid, radius = 150,
    point = { x = point.x, y = CIV.groundY(point), z = point.z },
  }
  return Fire.ignite(pt, severity)
end

local function extinguish(fire, byWhom)
  for _, eff in ipairs(fire.effects) do
    trigger.action.effectSmokeStop(eff.name)
  end
  fire.effects = {}
  CIV.unmark(fire.markId)
  CIV.unmark(fire.zoneMarkId)
  CIV.Pool.release(fire.pt)
  Fire._fires[fire.id] = nil
  releaseFireTrucks(fire)
  CIV.msgAll("Fire at " .. fire.pt.name .. " EXTINGUISHED" ..
    (byWhom and (" by " .. byWhom) or "") .. ".", 15)
end

-- command center: call a fire off without scoring
function Fire.callOff(fire)
  extinguish(fire, "the command center (called off)")
end

-- Apply suppression at a point (amount in severity units). Returns the
-- fire hit (or nil). Score attribution is the caller's job.
function Fire.applyWater(point, amount, byWhom)
  for _, fire in pairs(Fire._fires) do
    if CIV.dist2D(point, fire.point) <= CF.dropRadius then
      fire.severity = fire.severity - amount
      if fire.severity <= 0 then
        extinguish(fire, byWhom)
      else
        refreshVisuals(fire)
      end
      return fire
    end
  end
  return nil
end

-- growth + automatic ignition loop
local nextIgnition = timer.getTime() + CIV.randBetween(CF.autoIgnite)
CIV.schedule(function(_, t)
  local now = timer.getTime()
  for _, fire in pairs(Fire._fires) do
    if now >= fire.nextGrow and fire.severity < SEV.max then
      fire.severity = math.min(SEV.max, fire.severity + 1)
      fire.nextGrow = now + fire.growEvery
      refreshVisuals(fire)
      if fire.severity >= SEV.max then
        CIV.msgAll("Fire at " .. fire.pt.name ..
          " is RAGING (severity 10/10): all assets required.", 15)
      end
    end
  end
  if now >= nextIgnition then
    Fire.igniteRandom()
    nextIgnition = now + CIV.randBetween(CF.autoIgnite)
  end
  return t + 10
end, nil, 15)

----------------------------------------------------------------------
-- FIRE BRIGADE (scenic ground response)
-- Trucks depart from the nearest "CIVIL Fire Station" zone and drive to
-- the fire "On Road" (same stall watchdog as the police chase). On scene
-- they apply continuous suppression, cutting the air passes needed.
----------------------------------------------------------------------

local function truckRoute(brigade, fromPoint, firePoint)
  local g = Group.getByName(brigade.gname)
  if not g then return end
  pcall(function()
    g:getController():setTask({ id = "Mission", params = { route = { points = {
      { x = fromPoint.x, y = fromPoint.z, type = "Turning Point",
        action = brigade.roadAction, speed = CF.trucks.speed },
      { x = firePoint.x, y = firePoint.z, type = "Turning Point",
        action = brigade.roadAction, speed = CF.trucks.speed },
    } } } })
  end)
end

dispatchFireTrucks = function(fire)
  if not CF.trucks.enabled then return end
  local best, bestDist = nil, 1e12
  for _, pt in ipairs(CIV.Pool.load(C.zones.fireStations)) do
    local d = CIV.dist2D(pt.point, fire.point)
    if d < bestDist then best, bestDist = pt, d end
  end
  if not best then return end
  local gname = CIV.spawnGround(best.point, CF.trucks.count,
    C.templates.fireTruck, C.fallbackTypes.fireTruck, "CIVIL_FIRETRUCK")
  fire.brigade = {
    gname = gname, station = best, arrived = false,
    roadAction = "On Road", lastPos = nil, stalledSince = nil, rekicks = 0,
  }
  CIV.schedule(function() truckRoute(fire.brigade, best.point, fire.point) end, nil, 2)
  CIV.msgAll("Fire brigade rolling out of " .. best.name .. " towards " ..
    fire.pt.name .. ".", 12)
end

releaseFireTrucks = function(fire)
  if not fire.brigade then return end
  local gname = fire.brigade.gname
  fire.brigade = nil
  -- scenic pause on scene, then the trucks are cleared
  CIV.schedule(function() CIV.despawnGroup(gname) end, nil, 120)
end

-- brigade loop: arrival detection, ground suppression, stall watchdog
CIV.schedule(function(_, t)
  local now = timer.getTime()
  for _, fire in pairs(Fire._fires) do
    local b = fire.brigade
    if b then
      local g = Group.getByName(b.gname)
      local u = g and g:getUnit(1)
      if not u or not u:isExist() then
        fire.brigade = nil
      else
        local p = u:getPoint()
        if not b.arrived then
          if CIV.dist2D(p, fire.point) <= CF.trucks.suppressRadius then
            b.arrived = true
            CIV.msgAll("Fire brigade ON SCENE at " .. fire.pt.name ..
              ": ground suppression in progress.", 12)
          else
            -- stall watchdog (known "On Road" bug, same pattern as the chase)
            if b.lastPos and CIV.dist2D(p, b.lastPos) < 5 then
              b.stalledSince = b.stalledSince or now
              if now - b.stalledSince > 60 then
                b.stalledSince = nil
                b.rekicks = b.rekicks + 1
                if b.rekicks >= 2 then b.roadAction = "Off Road" end
                truckRoute(b, p, fire.point)
                CIV.dbg("Fire brigade re-kicked towards " .. fire.pt.name)
              end
            else
              b.stalledSince = nil
            end
            b.lastPos = { x = p.x, y = p.y, z = p.z }
          end
        else
          -- 10 s tick: suppressPerMin / 6 severity per tick
          fire.severity = fire.severity - CF.trucks.suppressPerMin / 6
          if fire.severity <= 0 then
            extinguish(fire, "the fire brigade")
          else
            refreshVisuals(fire)
          end
        end
      end
    end
  end
  return t + 10
end, nil, 20)

----------------------------------------------------------------------
-- HELICOPTER WATER OPS
----------------------------------------------------------------------

local heloState = {}   -- unitName -> { water = bool, cargoName = string|nil }

local function hState(uname)
  heloState[uname] = heloState[uname] or { water = false }
  return heloState[uname]
end

local function nearestWaterPoint(p)
  for _, pt in ipairs(CIV.Pool.load(C.zones.waterPoints)) do
    if CIV.dist2D(p, pt.point) <= math.max(pt.radius, 200) then return pt end
  end
  return nil
end

local function startWaterPickup(uname)
  local u = Unit.getByName(uname)
  if not u or not u:isExist() then return end
  local st = hState(uname)
  if st.water then
    CIV.msgUnit(u, "Tank already full: take the water to a fire.", 10)
    return
  end
  local pt = nearestWaterPoint(u:getPoint())
  if not pt then
    CIV.msgUnit(u, "No water pickup point nearby.", 10)
    return
  end
  local hp = C.hover.waterPickup
  CIV.Hover.start({
    unitName = uname, center = pt.point, label = "Water pickup",
    radius = hp.radius, minAGL = hp.minAGL, maxAGL = hp.maxAGL,
    maxSpeed = hp.maxSpeed, T = hp.T, window = hp.window, B = hp.B,
    onSuccess = function(unit)
      if CF.usePhysicalCargo then
        -- EXPERIMENTAL: native mass cargo spawned on the water
        st.cargoName = CIV.spawnCargo(pt.point, CF.waterCargoType, CF.waterCargoKg, "CIVIL_WATER")
        CIV.msgUnit(unit, "Water bag ready (" .. CF.waterCargoKg ..
          " kg). Hook it with the sling load system (F8).", 15)
      else
        st.water = true
        CIV.msgUnit(unit, "Water loaded. Fly to an active fire and use " ..
          "F10 -> Civil Missions -> Firefighting -> Drop water.", 15)
      end
    end,
    onFail = function()
      local u2 = Unit.getByName(uname)
      if u2 then CIV.msgUnit(u2, "Water pickup failed: time expired.", 10) end
    end,
  })
  CIV.msgUnit(u, "Hold your hover over the pickup point (" ..
    hp.minAGL .. "-" .. hp.maxAGL .. " m AGL).", 10)
end

local function dropWater(uname)
  local u = Unit.getByName(uname)
  if not u or not u:isExist() then return end
  local st = hState(uname)
  if not st.water then
    CIV.msgUnit(u, "Tank empty: pick up water at a CIVIL Water Point first.", 10)
    return
  end
  local info = CIV.players[uname]
  local fire = Fire.applyWater(u:getPoint(), CF.heloDropSeverity, info and info.playerName)
  st.water = false
  if fire then
    CIV.msgUnit(u, "Drop on target!", 10)
    if info then
      -- fire still burning: partial credit; extinguished: full credit.
      -- Score scales with the severity the fire had when hit.
      local preHit = fire.severity + CF.heloDropSeverity
      CIV.Score.award(info.playerName, "fireHelo",
        Fire._fires[fire.id] and 0.5 or 1.0, 0.5,
        CIV.severityMult(preHit), "firefighting drop")
    end
  else
    CIV.msgUnit(u, "Drop missed: no fire within " .. CF.dropRadius ..
      " m. Water wasted.", 10)
  end
end

-- physical cargo mode: delivery detected by polling the cargo position
-- (a slung cargo moves with the aircraft). TO TEST in-game.
CIV.schedule(function(_, t)
  if not CF.usePhysicalCargo then return t + 30 end
  for uname, st in pairs(heloState) do
    if st.cargoName then
      local s = StaticObject.getByName(st.cargoName)
      if not s then
        st.cargoName = nil   -- destroyed / dropped badly
      else
        local p = s:getPoint()
        for _, fire in pairs(Fire.actives()) do
          if CIV.dist2D(p, fire.point) <= CF.dropRadius and CIV.agl(p) < 5 then
            CIV.despawnStatic(st.cargoName)
            st.cargoName = nil
            local info = CIV.players[uname]
            local preHit = fire.severity
            Fire.applyWater(fire.point, CF.heloDropSeverity, info and info.playerName)
            if info then
              CIV.Score.award(info.playerName, "fireHelo", 1.0, 0.5,
                CIV.severityMult(preHit), "firefighting drop")
            end
            break
          end
        end
      end
    end
  end
  return t + 2
end, nil, 10)

----------------------------------------------------------------------
-- C-130 RETARDANT OPS + SPOTTER
----------------------------------------------------------------------

local c130State = {}   -- unitName -> { retardant, loading, dropRun }

local function cState(uname)
  c130State[uname] = c130State[uname] or { retardant = false }
  return c130State[uname]
end

local function isAirplane(info)
  return info.category == Unit.Category.AIRPLANE
end

-- Ground reload, OPT-IN via F10: nothing happens by just parking in the
-- reload zone, so a C-130 that only wants to orbit as spotter/rescue
-- support takes off clean with no interaction. Requesting the load starts
-- a hold timer; moving before it expires aborts the loading.
local function stoppedInReloadZone(u)
  local zone = CIV.Zones.byName(C.zones.c130Reload)
  if not zone then return false end
  return (not u:inAir()) and CIV.speed(u:getVelocity()) < 1
    and CIV.Zones.contains(zone, u:getPoint())
end

local function loadRetardant(uname)
  local u = Unit.getByName(uname)
  if not u or not u:isExist() then return end
  local st = cState(uname)
  if st.retardant then
    CIV.msgUnit(u, "Retardant already aboard.", 10)
    return
  end
  if st.loading then
    CIV.msgUnit(u, "Loading already in progress: stay put.", 10)
    return
  end
  if not stoppedInReloadZone(u) then
    CIV.msgUnit(u, "You must be LANDED and stationary inside the " ..
      C.zones.c130Reload .. " zone.", 10)
    return
  end
  st.loading = true
  CIV.msgUnit(u, "Loading retardant drums: stay put for " ..
    CF.c130ReloadTime .. " seconds.", 12)
  CIV.schedule(function()
    st.loading = false
    local u2 = Unit.getByName(uname)
    if not u2 or not u2:isExist() then return end
    if not stoppedInReloadZone(u2) then
      CIV.msgUnit(u2, "Loading aborted: you moved before the drums were secured.", 10)
      return
    end
    st.retardant = true
    CIV.msgUnit(u2, "Retardant loaded. Drop: F10 -> Civil Missions -> " ..
      "Firefighting C-130 -> Start line drop (altitude " ..
      CF.c130DropAGL.min .. "-" .. CF.c130DropAGL.max .. " m AGL).", 15)
  end, nil, CF.c130ReloadTime)
end

local function startLineDrop(uname)
  local u = Unit.getByName(uname)
  if not u or not u:isExist() then return end
  local st = cState(uname)
  if not st.retardant then
    CIV.msgUnit(u, "No retardant aboard: reload on the ground in the " ..
      C.zones.c130Reload .. " zone.", 10)
    return
  end
  local region = CIV.Zones.byName(C.zones.fireRegion)
  local p = u:getPoint()
  if region and not CIV.Zones.contains(region, p) then
    CIV.msgUnit(u, "You are outside the fire region.", 10)
    return
  end
  local agl = CIV.agl(p)
  if agl < CF.c130DropAGL.min or agl > CF.c130DropAGL.max then
    CIV.msgUnit(u, string.format("Invalid altitude (%d m AGL): drop band is %d-%d m.",
      math.floor(agl), CF.c130DropAGL.min, CF.c130DropAGL.max), 10)
    return
  end
  st.retardant = false
  st.dropRun = { endTime = timer.getTime() + CF.c130DropSeconds, hits = 0, maxSev = 1 }
  CIV.msgUnit(u, "DROP IN PROGRESS: hold heading and altitude for " ..
    CF.c130DropSeconds .. " seconds.", 10)
end

-- line drop tick: applies retardant along the flight path
CIV.schedule(function(_, t)
  local now = timer.getTime()
  for uname, st in pairs(c130State) do
    if st.dropRun then
      local u = Unit.getByName(uname)
      if not u or not u:isExist() or now > st.dropRun.endTime then
        local hits, maxSev = st.dropRun.hits, st.dropRun.maxSev
        st.dropRun = nil
        if u and u:isExist() then
          local info = CIV.players[uname]
          if hits > 0 and info then
            CIV.msgUnit(u, "Drop complete: effective line.", 10)
            CIV.Score.award(info.playerName, "fireC130",
              math.min(1, hits / CF.c130DropSeconds), 0.5,
              CIV.severityMult(maxSev), "C-130 retardant line")
          elseif u then
            CIV.msgUnit(u, "Drop complete: no fire under the line.", 10)
          end
        end
      else
        local p = u:getPoint()
        local agl = CIV.agl(p)
        if agl >= CF.c130DropAGL.min and agl <= CF.c130DropAGL.max then
          local info = CIV.players[uname]
          local fire = Fire.applyWater(p, CF.c130DropPerSec, info and info.playerName)
          if fire then
            st.dropRun.hits = st.dropRun.hits + 1
            st.dropRun.maxSev = math.max(st.dropRun.maxSev,
              fire.severity + CF.c130DropPerSec)
          end
        end
      end
    end
  end
  return t + 1
end, nil, 10)

----------------------------------------------------------------------
-- RETARDANT AIRDROP (official C-130 module, drum/barrel type crates)
-- Channel 1 (S_EVENT_SHOT weapon tracking) is shared: this file only
-- registers a consumer with CIV.Airdrop. Channel 2 scans for foreign
-- cargo/static objects appearing near active fires. Crate types and the
-- triggering channel are TO VALIDATE against the official module.
----------------------------------------------------------------------

if CF.airdrop.enabled then
  local matchesType = CIV.Airdrop.typeMatcher(CF.airdrop.containerTypes)

  local function retardantOnTarget(impact)
    local playerInfo = CIV.nearestPlayerAirplane(impact, CF.airdrop.creditRadius)
    local fire = Fire.applyWater(impact, CF.airdrop.severityPerContainer,
      playerInfo and playerInfo.playerName)
    if fire and playerInfo then
      local preHit = fire.severity + CF.airdrop.severityPerContainer
      CIV.Score.award(playerInfo.playerName, "fireC130",
        Fire._fires[fire.id] and 0.6 or 1.0, 0.5,
        CIV.severityMult(preHit), "retardant airdrop")
    end
    return fire ~= nil
  end

  CIV.Airdrop.register({
    key = "fire", matchesType = matchesType,
    matchAny = CF.airdrop.matchAnyObject,
    onImpact = function(point) return retardantOnTarget(point) end,
  })

  -- Channel 2: foreign objects near active fires (template spawns are all
  -- named "CIVIL_*" and skipped)
  local processedObjects = {}
  CIV.schedule(function(_, t)
    if not (world.searchObjects and world.VolumeType and Object and Object.Category) then
      return t + 60
    end
    for _, fire in pairs(Fire.actives()) do
      local volume = { id = world.VolumeType.SPHERE,
                       params = { point = fire.point, radius = CF.dropRadius } }
      pcall(world.searchObjects, Object.Category.STATIC, volume, function(obj)
        local ok, name = pcall(function() return obj:getName() end)
        if ok and name and not processedObjects[name]
           and string.sub(tostring(name), 1, 6) ~= "CIVIL_" then
          processedObjects[name] = true
          local okT, typeName = pcall(function() return obj:getTypeName() end)
          if CF.airdrop.matchAnyObject or (okT and typeName and matchesType(typeName)) then
            CIV.dbg("Foreign cargo object near fire: " .. tostring(name))
            local ok2, p = pcall(function() return obj:getPoint() end)
            if ok2 and p then retardantOnTarget(p) end
          end
        end
        return true
      end)
    end
    return t + 5
  end, nil, 10)
end

-- spotter: any player airplane inside the fire region relays fire intel
CIV.schedule(function(_, t)
  local region = CIV.Zones.byName(C.zones.fireRegion)
  if not region then return t + 120 end
  local spotter = nil
  CIV.forEachPlayer(function(u, info)
    if spotter then return end
    if isAirplane(info) and u:inAir() and CIV.Zones.contains(region, u:getPoint()) then
      spotter = info
    end
  end)
  if spotter then
    local n, txt = 0, ""
    for _, fire in pairs(Fire.actives()) do
      n = n + 1
      txt = txt .. string.format("- %s: %s (%s)\n", fire.pt.name,
        CIV.llString(fire.point), Fire.severityLabel(fire))
      if not fire.markId then
        fire.markId = CIV.mark(string.upper(fire.kindDef.name) .. " " ..
          fire.pt.name, fire.point)
      end
    end
    if n > 0 then
      CIV.msgAll("SPOTTER " .. spotter.playerName .. " reports " .. n ..
        " active fires:\n" .. txt, 20)
    end
  end
  return t + CF.spotterInterval
end, nil, 30)

----------------------------------------------------------------------
-- F10 MENUS + EVENT STARTER
----------------------------------------------------------------------

CIV.Menu_register(function(gid, uname)
  local heloSub = missionCommands.addSubMenuForGroup(gid, "Firefighting", CIV.rootMenu[gid])
  missionCommands.addCommandForGroup(gid, "Start water pickup", heloSub, startWaterPickup, uname)
  missionCommands.addCommandForGroup(gid, "Drop water", heloSub, dropWater, uname)
  missionCommands.addCommandForGroup(gid, "Active fires", heloSub, function()
    local n, txt = 0, "Active fires:\n"
    for _, fire in pairs(Fire.actives()) do
      n = n + 1
      local brigade = fire.brigade
        and (fire.brigade.arrived and "  [brigade on scene]" or "  [brigade en route]")
        or ""
      txt = txt .. string.format("- %s  %s  %s%s\n", fire.pt.name,
        Fire.severityLabel(fire), CIV.llString(fire.point), brigade)
    end
    CIV.msgGroupId(gid, n > 0 and txt or "No active fires.", 20)
  end)
  local c130Sub = missionCommands.addSubMenuForGroup(gid, "Firefighting C-130", CIV.rootMenu[gid])
  missionCommands.addCommandForGroup(gid, "Load retardant (at reload zone)", c130Sub, loadRetardant, uname)
  missionCommands.addCommandForGroup(gid, "Start line drop", c130Sub, startLineDrop, uname)
  missionCommands.addCommandForGroup(gid, "Retardant status", c130Sub, function()
    local st = cState(uname)
    local txt = st.retardant and "Retardant aboard."
      or (st.loading and "Loading in progress: stay put." or "No retardant aboard.")
    CIV.msgGroupId(gid, txt, 10)
  end)
end)

CIV.EventStarters.fire = { label = "Wildfire", fn = Fire.igniteRandom }

CIV.log("CivilFirefighting loaded")

-- ====================================================================
-- >>> Scripts/20_CivilRescue.lua
-- ====================================================================
----------------------------------------------------------------------
-- DCS Civil Mission Template - Rescue (SAR Mountain, SAR Sea, MedEvac)
-- File: 20_CivilRescue.lua  (requires 01_CivilCore.lua)
--
-- One generic rescue engine, three scenarios. Beacon/frequency logic and
-- survivor smoke marking adapted from the 527th CSAR System.
--
-- Event cycle:
--   spawn subject on a pool point (from "CIVIL Survivor"/"CIVIL Boat"
--   template if present, else fallback type) -> optional radio beacon
--   (homing only on Mi-8/UH-1H/SA342/AH-64D) -> extraction via hover watch
--   (first helicopter in the envelope gets the session) -> subject
--   despawned ("aboard") -> zone based delivery at a "CIVIL Hospital" pad
--   (hold low & still for N s).
--
-- Intel model: exact coordinates are NEVER broadcast automatically. The
-- initial report gives a rough direction and an approximate search circle
-- on the F10 map (subject inside, NOT centered). The exact position is
-- released only when a player airplane (C-130 spotter) flies close enough
-- to identify the subject. Survivor smoke remains available on request.
--
-- VERIFIED (concept): S_EVENT_LAND only fires on recognized airbase/FARP/
-- ship objects, NOT on arbitrary pads -> delivery is zone-based, never
-- the LAND event.
--
-- MedEvac difference: a CRITICALITY deadline. Score quality is the
-- remaining criticality fraction at pickup; delivery after the deadline
-- (even with the casualty aboard) means the patient did not make it.
----------------------------------------------------------------------

assert(CIV and CIV.VERSION, "01_CivilCore.lua must be loaded first")

local C = CIV.Config

CIV.Rescue = { _scenarios = {}, _aboard = {} }   -- _aboard: unitName -> list of subjects
local R = CIV.Rescue

----------------------------------------------------------------------
-- SUBJECTS ABOARD
----------------------------------------------------------------------

function R.aboardList(uname)
  R._aboard[uname] = R._aboard[uname] or {}
  return R._aboard[uname]
end

----------------------------------------------------------------------
-- SCENARIO ENGINE
-- def = { key, label, poolPrefix, region, maxActive, kind ("ground"|"boat"),
--         beacon, scoreType, hoverCfg, deadline (s, optional),
--         qualityFn(evt, session) optional }
----------------------------------------------------------------------

function R.newScenario(def)
  local sc = { def = def, events = {}, _eid = 0 }
  R._scenarios[def.key] = sc
  return sc
end

local function startBeacon(def, evt)
  local b = def.beacon
  if not (b and b.enabled) then return end
  -- needs the .ogg inside the .miz; homing works only on some modules
  evt.beaconName = "CIVIL_BCN_" .. def.key .. "_" .. evt.id
  local ok, err = pcall(trigger.action.radioTransmission,
    b.file, evt.point, b.modulation or 1, true, b.freqHz, b.power or 100, evt.beaconName)
  if not ok then
    CIV.log("Beacon failed (" .. tostring(err) .. "): falling back to text coordinates")
    evt.beaconName = nil
  end
end

local function stopBeacon(evt)
  if evt.beaconName then
    pcall(trigger.action.stopRadioTransmission, evt.beaconName)
    evt.beaconName = nil
  end
end

----------------------------------------------------------------------
-- AI SAR VESSELS
-- Ship groups placed in the ME (group name prefix rescue.vessels.
-- groupPrefix) steam toward the APPROXIMATE search area when a sea event
-- starts (they get the same low-precision intel as the players) and are
-- re-tasked to the exact point once a spotter identifies the subject.
----------------------------------------------------------------------

local vesselBusy = {}   -- groupName -> event id currently served

local function taskVessel(gname, point, speed)
  local g = Group.getByName(gname)
  if not g then return false end
  local ok = pcall(function()
    g:getController():setTask({ id = "Mission", params = { route = { points = {
      { x = point.x, y = point.z, type = "Turning Point", speed = speed },
    } } } })
  end)
  return ok
end

-- Nearest launch origin for spawned boats: mother ships (the hospital-ship
-- units, e.g. a Perry or a Tarawa) or "CIVIL Vessel Spawn" harbor zones.
local function nearestBoatOrigin(point)
  local best, bestDist = nil, 1e12
  for _, ship in ipairs(CIV.Ships) do
    if CIV.startsWith(ship.unitName, C.rescue.hospitalShips.unitPrefix) then
      local su = Unit.getByName(ship.unitName)
      if su and su:isExist() then
        local sp = su:getPoint()
        local d = CIV.dist2D(sp, point)
        if d < bestDist then
          best, bestDist = { point = sp, name = ship.unitName, isShip = true }, d
        end
      end
    end
  end
  for _, pt in ipairs(CIV.Pool.load(C.zones.vesselSpawn)) do
    local d = CIV.dist2D(pt.point, point)
    if d < bestDist then
      best, bestDist = { point = pt.point, name = pt.name, isShip = false }, d
    end
  end
  return best
end

local function dispatchVessels(evt)
  local vcfg = C.rescue.vessels
  if not vcfg.enabled then return end
  local seen, candidates = {}, {}
  for _, ship in ipairs(CIV.Ships) do
    local gname = ship.groupName
    if not seen[gname] and CIV.startsWith(gname, vcfg.groupPrefix)
       and not vesselBusy[gname] then
      seen[gname] = true
      local g = Group.getByName(gname)
      local u = g and g:getUnit(1)
      if u and u:isExist() then
        candidates[#candidates + 1] = {
          gname = gname, dist = CIV.dist2D(u:getPoint(), evt.approxCenter),
        }
      end
    end
  end
  table.sort(candidates, function(a, b) return a.dist < b.dist end)
  evt.vessels = {}
  for _, cand in ipairs(candidates) do
    if #evt.vessels >= vcfg.perEvent then break end
    if taskVessel(cand.gname, evt.approxCenter, vcfg.speed) then
      vesselBusy[cand.gname] = evt.id
      evt.vessels[#evt.vessels + 1] = cand.gname
    end
  end
  -- not enough pre-placed vessels: launch stock boats from the nearest
  -- origin (mother ship if it is closer than the harbors)
  evt.spawnedVessels = {}
  if vcfg.spawn.enabled and #evt.vessels < vcfg.perEvent then
    local origin = nearestBoatOrigin(evt.approxCenter)
    if origin then
      local launchPoint = origin.point
      if origin.isShip then
        -- clear of the mother ship's hull, offset toward the event
        launchPoint = CIV.offsetPoint(origin.point,
          CIV.bearingDeg(origin.point, evt.approxCenter), vcfg.spawn.offsetFromShip)
      end
      while #evt.vessels < vcfg.perEvent do
        local gname = CIV.spawnBoat(launchPoint, "CIVIL_RESCUEBOAT",
          C.templates.vessel, C.fallbackTypes.rescueBoat)
        evt.vessels[#evt.vessels + 1] = gname
        evt.spawnedVessels[#evt.spawnedVessels + 1] = gname
        CIV.schedule(function() taskVessel(gname, evt.approxCenter, vcfg.speed) end, nil, 2)
      end
      CIV.msgAll("Rescue boat(s) launched from " .. origin.name .. ".", 12)
    end
  end
  if #evt.vessels > 0 then
    CIV.msgAll(#evt.vessels .. " rescue vessel(s) underway to the search area.", 12)
  end
end

local function retaskVessels(evt, point)
  for _, gname in ipairs(evt.vessels or {}) do
    taskVessel(gname, point, C.rescue.vessels.speed)
  end
end

local function releaseVessels(evt)
  for _, gname in ipairs(evt.vessels or {}) do
    vesselBusy[gname] = nil
  end
  -- spawned boats are despawned after a scenic delay; pre-placed ones stay
  for _, gname in ipairs(evt.spawnedVessels or {}) do
    CIV.schedule(function() CIV.despawnGroup(gname) end, nil, 120)
  end
  evt.vessels = nil
  evt.spawnedVessels = nil
end

-- Scene dressing next to the casualty (ambulance and medics, wrecked
-- cars, battlefield props: whatever the matching ME template contains).
-- One random entry from the scenario's list, then one random template
-- among those sharing that prefix.
local function spawnScene(def, evt)
  local sceneList = C.rescue.scenes.byScenario[def.key]
  if not sceneList or #sceneList == 0 then return end
  local prefix = sceneList[math.random(#sceneList)]
  local scenePoint = CIV.offsetPoint(evt.point, math.random(0, 359),
    C.rescue.scenes.offsetM)
  local gname = CIV.spawnFromTemplate(prefix, scenePoint)
  if gname then
    evt.sceneGname = gname
    CIV.dbg("Scene '" .. prefix .. "' spawned for " .. def.key .. " #" .. evt.id)
  else
    CIV.dbg("No scene template found for prefix '" .. prefix .. "'")
  end
end

-- The scene lingers for a while after the event ends, then it is cleared
local function releaseScene(evt)
  if not evt.sceneGname then return end
  local gname = evt.sceneGname
  evt.sceneGname = nil
  CIV.schedule(function() CIV.despawnGroup(gname) end,
    nil, C.rescue.scenes.despawnDelay)
end

local function closeEvent(sc, evt)
  sc.events[evt.id] = nil
  CIV.Pool.release(evt.pt)
  stopBeacon(evt)
  releaseVessels(evt)
  releaseScene(evt)
  CIV.unmark(evt.markId)
  CIV.unmark(evt.circleId)
  if evt.gname then CIV.despawnGroup(evt.gname) end
end

-- command center: close an event without any outcome
function R.cancel(evt)
  local sc = R._scenarios[evt.scKey]
  if sc and sc.events[evt.id] then
    if evt.watch then CIV.Hover.unwatch(evt.watch) end
    closeEvent(sc, evt)
    return true
  end
  return false
end

-- reference point/name for the low-precision initial report: the scenario
-- region if defined, otherwise the nearest hospital pad
local function vagueReference(def, point)
  local region = def.region and CIV.Zones.byName(def.region)
  if region then
    return { x = region.center.x, z = region.center.z }, region.name
  end
  local best, bestDist = nil, 1e12
  for _, pt in ipairs(CIV.Pool.load(C.zones.hospitals)) do
    local d = CIV.dist2D(point, pt.point)
    if d < bestDist then best, bestDist = pt, d end
  end
  if best then return best.point, best.name end
  return nil, nil
end

-- opts (command center): { point = vec3, severity = 1..10 }
function R.startEvent(key, opts)
  local sc = R._scenarios[key]
  if not sc then return nil end
  local def = sc.def
  local n = 0
  for _ in pairs(sc.events) do n = n + 1 end
  if not (opts and opts.point) and n >= def.maxActive then return nil end

  local pt
  if opts and opts.point then
    -- commanded position instead of the curated pool
    if def.kind == "boat" and not CIV.isWater(opts.point) then
      CIV.msgAll(def.label .. ": commanded position is not on open water.", 10)
      return nil
    end
    sc._gmid = (sc._gmid or 0) + 1
    pt = {
      name = "GM " .. def.key .. " " .. sc._gmid, radius = 100,
      point = { x = opts.point.x, y = CIV.groundY(opts.point), z = opts.point.z },
    }
  else
    pt = CIV.Pool.pick(def.poolPrefix, 1000)
    if not pt then
      CIV.dbg("Rescue " .. key .. ": no free point in pool " .. def.poolPrefix)
      return nil
    end
  end

  sc._eid = sc._eid + 1
  -- one severity roll shapes the whole event: deadline, hover envelope, score
  local sev = (opts and opts.severity)
    and math.max(1, math.min(10, opts.severity))
    or CIV.rollSeverity(def.severityRange)
  local se = C.rescue.severityEffects
  local evt = {
    id = sc._eid, pt = pt, point = pt.point,
    severity = sev, scKey = def.key,
    spawnTime = timer.getTime(),
  }
  if def.deadline then
    evt.deadlineTotal = def.deadline
      * CIV.sevLerp(sev, se.deadlineFactor.atMin, se.deadlineFactor.atMax)
    evt.deadline = timer.getTime() + evt.deadlineTotal
  end
  if def.kind == "boat" then
    evt.gname = CIV.spawnBoat(pt.point, "CIVIL_" .. def.key)
  else
    evt.gname = CIV.spawnGround(pt.point, 1,
      def.templatePrefix or C.templates.survivor,
      C.fallbackTypes.survivor, "CIVIL_" .. def.key)
  end
  startBeacon(def, evt)
  spawnScene(def, evt)
  sc.events[evt.id] = evt
  CIV.Pool.occupy(pt)

  -- Approximate search circle (CSAR opponent-intel style): the subject is
  -- inside the circle but NOT at its center, and the radius is random.
  local intel = C.rescue.intel
  local circleRadius = CIV.randBetween(intel.approxRadius)
  local circleCenter = CIV.offsetPoint(evt.point, math.random(0, 359),
    circleRadius * CIV.randBetween(intel.centerOffset))
  evt.approxCenter = circleCenter
  evt.circleId = CIV.markCircle(circleCenter,
    def.label .. " #" .. evt.id .. " search area", circleRadius)
  evt.identified = false
  if def.kind == "boat" then dispatchVessels(evt) end

  local refPoint, refName = vagueReference(def, evt.point)
  evt.vagueText = refPoint
    and CIV.vagueDirection(refPoint, refName, evt.point)
    or "position unknown"

  local msg = def.label .. " (severity " .. sev .. "/10): subject awaiting " ..
    "recovery, " .. evt.vagueText ..
    ".\nApproximate search area marked on the F10 map. Exact position " ..
    "requires a spotter aircraft overhead (or request smoke when close)."
  if evt.beaconName then
    msg = msg .. string.format("\nBeacon active on %.3f MHz", def.beacon.freqHz / 1e6)
  end
  if evt.deadline then
    msg = msg .. string.format("\nCriticality: %d minutes", math.floor(evt.deadlineTotal / 60))
  end
  CIV.msgAll(msg, 25)

  -- severity shapes the hover envelope: less window, more required time
  local hp = def.hoverCfg
  local windowS = hp.window * CIV.sevLerp(sev, se.windowFactor.atMin, se.windowFactor.atMax)
  local requiredT = hp.T * CIV.sevLerp(sev, se.tFactor.atMin, se.tFactor.atMax)
  evt.watch = CIV.Hover.watch({
    center = evt.point, label = def.label .. " - extraction",
    radius = hp.radius, minAGL = hp.minAGL, maxAGL = hp.maxAGL,
    maxSpeed = hp.maxSpeed, T = requiredT, window = windowS, B = hp.B,
    onSuccess = function(unit, session)
      -- despawn = loaded aboard; delivery just consumes the state flag.
      -- The scene assets stay a few more minutes, then they pack up.
      CIV.despawnGroup(evt.gname)
      evt.gname = nil
      stopBeacon(evt)
      releaseVessels(evt)
      releaseScene(evt)
      table.insert(R.aboardList(unit:getName()), {
        scoreType = def.scoreType, label = def.label, evt = evt,
        quality = def.qualityFn and def.qualityFn(evt, session)
                  or CIV.Score.hoverQuality(session),
        timeFactor = CIV.Score.hoverTimeFactor(session),
        mult = CIV.severityMult(evt.severity),
      })
      sc.events[evt.id] = nil
      CIV.Pool.release(evt.pt)
      CIV.unmark(evt.markId)
      CIV.unmark(evt.circleId)
      CIV.msgUnit(unit, def.label .. ": subject ABOARD. Deliver to a " ..
        "hospital pad (" .. C.zones.hospitals .. " zones): hold low and " ..
        "still for " .. C.rescue.delivery.holdSeconds .. " seconds.", 20)
    end,
    onFail = function()
      -- Sea events with vessels en route are NOT lost yet: the event stays
      -- alive for one extra window so the boats can complete the rescue
      -- (spotter credit). Everything else fails as before.
      if def.kind == "boat" and evt.vessels and #evt.vessels > 0 then
        evt.heloFailed = true
        evt.hardDeadline = timer.getTime() + windowS
        CIV.msgAll(def.label .. ": helicopter recovery window EXPIRED at " ..
          pt.name .. ". Rescue vessels are still en route: the subject is " ..
          "holding on for now.", 20)
      else
        CIV.msgAll(def.label .. ": recovery FAILED at " .. pt.name ..
          " (window expired). The subject did not make it.", 20)
        closeEvent(sc, evt)
      end
    end,
  })
  CIV.log("Rescue " .. key .. " event #" .. evt.id .. " at " .. pt.name)
  return evt
end

----------------------------------------------------------------------
-- HOSPITAL DELIVERY (zone-based: still & low inside a hospital zone)
----------------------------------------------------------------------

local deliveryTimer = {}   -- unitName -> time the valid dwell started

-- Mobile hospital ship check: everything is measured RELATIVE to the ship
-- unit (it may be underway): horizontal distance, altitude above the ship
-- reference point within deck bounds, and relative speed.
local function onHospitalShip(u, p)
  local hcfg = C.rescue.hospitalShips
  if not hcfg.enabled then return false end
  for _, ship in ipairs(CIV.Ships) do
    if CIV.startsWith(ship.unitName, hcfg.unitPrefix) then
      local su = Unit.getByName(ship.unitName)
      if su and su:isExist() then
        local sp = su:getPoint()
        if CIV.dist2D(p, sp) <= hcfg.radius then
          local hv, sv = u:getVelocity(), su:getVelocity()
          local relSpeed = CIV.speed({ x = hv.x - sv.x, y = hv.y - sv.y, z = hv.z - sv.z })
          local deckHeight = p.y - sp.y
          if relSpeed <= hcfg.maxRelSpeed
             and deckHeight >= -5 and deckHeight <= hcfg.deckAGLMax then
            return true
          end
        end
      end
    end
  end
  return false
end

CIV.schedule(function(_, t)
  local cd = C.rescue.delivery
  local now = timer.getTime()
  for uname, list in pairs(R._aboard) do
    if #list > 0 then
      local u = Unit.getByName(uname)
      if u and u:isExist() then
        local p = u:getPoint()
        local inHospital = false
        for _, pt in ipairs(CIV.Pool.load(C.zones.hospitals)) do
          if CIV.dist2D(p, pt.point) <= math.max(pt.radius, cd.radius) then
            inHospital = true
            break
          end
        end
        local stillAndLow = CIV.speed(u:getVelocity()) <= cd.maxSpeed
          and CIV.agl(p) <= cd.maxAGL
        if (inHospital and stillAndLow) or onHospitalShip(u, p) then
          deliveryTimer[uname] = deliveryTimer[uname] or now
          if now - deliveryTimer[uname] >= cd.holdSeconds then
            deliveryTimer[uname] = nil
            local info = CIV.players[uname]
            for _, subj in ipairs(list) do
              if subj.evt.deadline and now > subj.evt.deadline then
                CIV.msgUnit(u, subj.label .. ": the subject died before delivery.", 15)
              elseif info then
                CIV.Score.award(info.playerName, subj.scoreType,
                  subj.quality, subj.timeFactor, subj.mult or 1, subj.label)
              end
            end
            R._aboard[uname] = {}
            CIV.msgUnit(u, "Hospital delivery complete.", 15)
          end
        else
          deliveryTimer[uname] = nil
        end
      end
    end
  end
  return t + 2
end, nil, 10)

-- criticality deadline notification while aboard (MedEvac)
CIV.schedule(function(_, t)
  local now = timer.getTime()
  for uname, list in pairs(R._aboard) do
    for _, subj in ipairs(list) do
      if subj.evt.deadline and not subj.deathNotified and now > subj.evt.deadline then
        subj.deathNotified = true
        local u = Unit.getByName(uname)
        if u then
          CIV.msgUnit(u, subj.label .. ": criticality expired, the patient died aboard.", 15)
        end
      end
    end
  end
  return t + 10
end, nil, 20)

----------------------------------------------------------------------
-- SUBJECT SIGNAL ON REQUEST (all rescue variants share it)
-- Orange smoke by day; by night smoke is invisible, so the subject fires
-- a sequence of signal flares instead. CSAR-style visual mark.
----------------------------------------------------------------------

local function requestSignal(uname)
  local u = Unit.getByName(uname)
  if not u or not u:isExist() then return end
  local p = u:getPoint()
  local best, bestDist = nil, 15000   -- only within 15 km
  for _, sc in pairs(R._scenarios) do
    for _, evt in pairs(sc.events) do
      local d = CIV.dist2D(p, evt.point)
      if d < bestDist then best, bestDist = evt, d end
    end
  end
  if not best then
    CIV.msgUnit(u, "No rescue subject within 15 km.", 10)
    return
  end
  if CIV.isNight() then
    local sig = C.rescue.signal
    for i = 0, sig.flareCount - 1 do
      CIV.schedule(function()
        local fp = CIV.offsetPoint(best.point, math.random(0, 359), 5)
        pcall(trigger.action.signalFlare, fp,
          trigger.flareColor and trigger.flareColor.Green or 0,
          math.random(0, 359))
      end, nil, 1 + i * sig.flareIntervalSeconds)
    end
    CIV.msgUnit(u, "Subject is firing GREEN signal flares (" ..
      sig.flareCount .. " shots). Watch for them before pickup.", 12)
  else
    local sp = CIV.offsetPoint(best.point, math.random(0, 359), C.rescue.smokeOffsetM)
    trigger.action.smoke(sp, trigger.smokeColor.Orange)
    CIV.msgUnit(u, "Subject is marking position with ORANGE smoke. " ..
      "Confirm visual before pickup.", 12)
  end
end
R.requestSignal = requestSignal

----------------------------------------------------------------------
-- SPOTTER IDENTIFICATION
-- A subject stays unidentified (vague direction + approximate circle
-- only) until an airborne player airplane (C-130) either enters the
-- scenario region or flies within intel.spotterDetectRadius of the
-- subject. Identification is one-shot: it releases the exact position
-- and drops a point mark on the F10 map.
----------------------------------------------------------------------

CIV.schedule(function(_, t)
  local detectR = C.rescue.intel.spotterDetectRadius
  for _, sc in pairs(R._scenarios) do
    local region = sc.def.region and CIV.Zones.byName(sc.def.region)
    for _, evt in pairs(sc.events) do
      if not evt.identified then
        local spotter = nil
        CIV.forEachPlayer(function(u, info)
          if spotter then return end
          if info.category ~= Unit.Category.AIRPLANE or not u:inAir() then return end
          local p = u:getPoint()
          if (region and CIV.Zones.contains(region, p))
             or CIV.dist2D(p, evt.point) <= detectR then
            spotter = info
          end
        end)
        if spotter then
          evt.identified = true
          evt.spotterName = spotter.playerName   -- credited on a sea rescue
          evt.markId = CIV.mark(sc.def.label .. " #" .. evt.id, evt.point)
          retaskVessels(evt, evt.point)   -- vessels steer to the exact position
          CIV.msgAll("SPOTTER " .. spotter.playerName .. " has identified the " ..
            sc.def.label .. " #" .. evt.id .. " subject:\n" ..
            CIV.coordText(evt.point) .. "\nExact position marked on the F10 map.", 20)
        end
      end
    end
  end
  return t + 15
end, nil, 45)

----------------------------------------------------------------------
-- SEA RESCUE BY VESSEL
-- A vessel holding within rescueRadius of the subject for
-- rescueHoldSeconds completes the rescue by sea; the identifying spotter
-- gets the score (the C-130 made the sea rescue possible). Also enforces
-- the extended hard deadline after a failed helicopter window.
----------------------------------------------------------------------

CIV.schedule(function(_, t)
  local vcfg = C.rescue.vessels
  local now = timer.getTime()
  for _, sc in pairs(R._scenarios) do
    if sc.def.kind == "boat" then
      for _, evt in pairs(sc.events) do
        if evt.heloFailed and now > evt.hardDeadline then
          CIV.msgAll(sc.def.label .. ": the subject was lost at sea before " ..
            "the vessels could arrive.", 20)
          closeEvent(sc, evt)
        elseif evt.gname then
          local near = false
          for _, gname in ipairs(evt.vessels or {}) do
            local g = Group.getByName(gname)
            local u = g and g:getUnit(1)
            if u and u:isExist()
               and CIV.dist2D(u:getPoint(), evt.point) <= vcfg.rescueRadius then
              near = true
              break
            end
          end
          if near then
            evt.vesselNearSince = evt.vesselNearSince or now
            if now - evt.vesselNearSince >= vcfg.rescueHoldSeconds then
              if evt.watch then CIV.Hover.unwatch(evt.watch) end
              local msg = sc.def.label .. ": subject RECOVERED by a rescue vessel."
              if evt.spotterName then
                CIV.Score.award(evt.spotterName, sc.def.scoreType, 0.7, 0.5,
                  vcfg.spotterScoreMult * CIV.severityMult(evt.severity),
                  "sea rescue (spotter credit)")
              else
                msg = msg .. " No spotter on station: no credit assigned."
              end
              CIV.msgAll(msg, 20)
              closeEvent(sc, evt)
            end
          else
            evt.vesselNearSince = nil
          end
        end
      end
    end
  end
  return t + 5
end, nil, 25)

----------------------------------------------------------------------
-- SCENARIO INSTANCES
----------------------------------------------------------------------

-- quality = remaining criticality fraction at PICKUP time (delivery past
-- the deadline still voids the score, see the delivery loop). Uses the
-- severity-scaled per-event deadline.
local function criticalityQuality(evt)
  local left = evt.deadline - timer.getTime()
  return math.max(0, math.min(1, left / evt.deadlineTotal))
end

R.newScenario({
  key = "SAR_MOUNTAIN", label = "SAR Mountain", kind = "ground",
  poolPrefix = C.zones.sarMountainPoints, region = C.zones.sarMountainRegion,
  maxActive = C.rescue.sarMountain.maxActive, beacon = C.rescue.sarMountain.beacon,
  severityRange = C.rescue.sarMountain.severity,
  scoreType = "sarMountain", hoverCfg = C.hover.sarMountain,
})

R.newScenario({
  key = "SAR_SEA", label = "SAR Sea", kind = "boat",
  -- a floating unit on open water is a standard DCS use case: low risk
  poolPrefix = C.zones.sarSeaPoints, region = C.zones.sarSeaRegion,
  maxActive = C.rescue.sarSea.maxActive, beacon = C.rescue.sarSea.beacon,
  severityRange = C.rescue.sarSea.severity,
  scoreType = "sarSea", hoverCfg = C.hover.sarSea,
})

R.newScenario({
  key = "MEDEVAC", label = "MedEvac", kind = "ground",
  poolPrefix = C.zones.medevacPoints, region = nil,
  maxActive = C.rescue.medevac.maxActive, beacon = nil,
  severityRange = C.rescue.medevac.severity,
  scoreType = "medevac", hoverCfg = C.hover.medevac,
  deadline = C.rescue.medevac.criticality,
  qualityFn = criticalityQuality,
})

-- Battlefield casualty extraction: same flow as MedEvac (the concept
-- anticipated this reuse: same scheme, hostile narrative skin), with its
-- own LZ pool, casualty template, tighter criticality and score premium.
R.newScenario({
  key = "CASEVAC", label = "Battlefield CASEVAC", kind = "ground",
  poolPrefix = C.zones.casevacPoints, region = nil,
  maxActive = C.rescue.casevac.maxActive, beacon = nil,
  templatePrefix = C.templates.casualty,
  severityRange = C.rescue.casevac.severity,
  scoreType = "casevac", hoverCfg = C.hover.casevac,
  deadline = C.rescue.casevac.criticality,
  qualityFn = criticalityQuality,
})

